import requests
import json

def test_registered_device_batch_ingest_multiple_observations():
    cert_path = ('<cert_file>', '<key_file>')
    url = 'https://fhir-lite/Ingest'

    bundle_payload = {
        'resourceType': 'Bundle',
        'type': 'transaction',
        'entry': [
            {
                'resource': {
                    'resourceType': 'Observation',
                    'status': 'final',
                    'value': {'value': 98.6, 'unit': 'Cel'}
                }
            },
            {
                'resource': {
                    'resourceType': 'Observation',
                    'status': 'final',
                    'value': {'value': 72, 'unit': '/min'}
                }
            },
            {
                'resource': {
                    'resourceType': 'Observation',
                    'status': 'final',
                    'value': {'value': 120, 'unit': 'mmHg'}
                }
            }
        ]
    }

    resp = requests.post(
        url,
        json=bundle_payload,
        cert=cert_path,
        headers={'device_id': 'DEV-002'}
    )

    assert resp.status_code == 200
    data = resp.json()
    assert data.get('count') == 3
    assert data.get('batch_id') is not None
